    { id: "geo11_c2_h6", question: "What are the limitations of Köppen's climate classification system?", options: ["It doesn't account for local factors like altitude and ignores causes of climate", "It is too detailed", "It only works for tropical regions", "It requires satellite data"], correct: "It doesn't account for local factors like altitude and ignores causes of climate", explanation: "Köppen's system is purely empirical based on temperature and precipitation thresholds and doesn't explain why climates occur or account for local topographic effects.", difficulty: "Hard" },
    { id: "geo11_c2_h7", question: "How has climate change affected traditional climate zones?", options: ["Boundaries are shifting, some zones expanding while others shrink", "Climate zones are completely stable", "Only polar zones are affected", "No measurable changes have occurred"], correct: "Boundaries are shifting, some zones expanding while others shrink", explanation: "Climate change is causing arid zones to expand, temperate zones to shift poleward, and alpine zones to shrink, challenging traditional classification boundaries.", difficulty: "Hard" },
    { id: "geo11_c2_h8", question: "What is the 'Bereha' climate zone in Ethiopia?", options: ["Hot arid desert zone with temperatures exceeding 40°C", "Cool highland zone", "Wet tropical zone", "Temperate forest zone"], correct: "Hot arid desert zone with temperatures exceeding 40°C", explanation: "Bereha is the hot arid desert zone in Ethiopia, found in areas like the Danakil Depression, with extreme heat and minimal rainfall.", difficulty: "Hard" },
    { id: "geo11_c2_h9", question: "How do rain shadow effects create different climate zones on opposite sides of mountains?", options: ["Moist air rises and cools on windward side causing rain, dry air descends on leeward side", "Mountains block all wind", "Both sides receive equal rainfall", "Rain shadows only occur in deserts"], correct: "Moist air rises and cools on windward side causing rain, dry air descends on leeward side", explanation: "Orographic lifting forces moist air up on the windward side causing precipitation, while the descending air on the leeward side is dry, creating a rain shadow.", difficulty: "Hard" },
    { id: "geo11_c2_h10", question: "What role does albedo play in climate classification of different regions?", options: ["Surface reflectivity affects energy absorption, influencing regional temperatures", "Albedo only matters for polar regions", "Dark surfaces always create cold climates", "Albedo has no climate significance"], correct: "Surface reflectivity affects energy absorption, influencing regional temperatures", explanation: "Albedo (surface reflectivity) varies greatly between regions—snow/ice reflects more energy while forests absorb more, significantly influencing regional climate characteristics.", difficulty: "Hard" }
